#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int patrons[M][2];
        for (int i = 0; i < M; i++) {
            scanf("%d %d", &patrons[i][0], &patrons[i][1]);
        }
        int result = 0;
        // Greedy algorithm to find the maximum independent set
        while (1) {
            int minPatron = -1;
            int minCount = 1000000;
            for (int i = 0; i < M; i++) {
                int count = 0;
                for (int j = 0; j < M; j++) {
                    if (patrons[j][0] == patrons[i][0] || patrons[j][1] == patrons[i][0]) {
                        count++;
                    }
                }
                if (count < minCount) {
                    minCount = count;
                    minPatron = i;
                }
            }
            if (minPatron == -1) break;
            result++;
            // Remove all patrons who prefer the added dish
            for (int i = M - 1; i >= 0; i--) {
                if (patrons[i][0] == patrons[minPatron][0] || patrons[i][1] == patrons[minPatron][0]) {
                    for (int j = i; j < M - 1; j++) {
                        patrons[j][0] = patrons[j + 1][0];
                        patrons[j][1] = patrons[j + 1][1];
                    }
                    M--;
                }
            }
        }
        printf("%d\n", result);
    }
    return 0;
}

