        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            int M = scanner.nextInt();
            int[][] patrons = new int[M][2];
            for (int i = 0; i < M; i++) {
                patrons[i][0] = scanner.nextInt();
                patrons[i][1] = scanner.nextInt();
            }
            int result = 0;
            // Greedy algorithm to find the maximum independent set
            while (true) {
                int minPatron = -1;
                int minCount = 1000000;
                for (int i = 0; i < M; i++) {
                    int count = 0;
                    for (int j = 0; j < M; j++) {
                        if (patrons[j][0] == patrons[i][0] || patrons[j][1] == patrons[i][0]) {
                            count++;
                        }
                    }
                    if (count < minCount) {
                        minCount = count;
                        minPatron = i;
                    }
                }
                if (minPatron == -1) break;
                result++;
                // Remove all patrons who prefer the added dish
                int index = 0;
                for (int i = 0; i < M; i++) {
                    if (patrons[i][0] != patrons[minPatron][0] && patrons[i][1] != patrons[minPatron][0]) {
                        patrons[index][0] = patrons[i][0];
                        patrons[index][1] = patrons[i][1];
                        index++;
                    }
                }
                M = index;
            }
            System.out.println(result);
