const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => input[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, M] = readline().split(' ').map(Number);
    const patrons = [];
    for (let j = 0; j < M; j++) {
        patrons.push(readline().split(' ').map(Number));
    }
    let result = 0;
    // Greedy algorithm to find the maximum independent set
    while (true) {
        let minPatron = -1;
        let minCount = 1000000;
        for (let j = 0; j < M; j++) {
            let count = 0;
            for (let k = 0; k < M; k++) {
                if (patrons[k][0] === patrons[j][0] || patrons[k][1] === patrons[j][0]) {
                    count++;
                }
            }
            if (count < minCount) {
                minCount = count;
                minPatron = j;
            }
        }
        if (minPatron === -1) break;
        result++;
        // Remove all patrons who prefer the added dish
        const newPatrons = [];
        for (let j = 0; j < M; j++) {
            if (patrons[j][0] !== patrons[minPatron][0] && patrons[j][1] !== patrons[minPatron][0]) {
                newPatrons.push(patrons[j]);
            }
        }
        patrons.length = 0;
        patrons.push(...newPatrons);
        M = patrons.length;
    }
    console.log(result);
}
